    dailyDateH1Template: '{NAME} ({WESTERN_NAME}) Horoscope  –  {WEEKDAY}, {DATE}',
    // Daily-date overall-score line
    overallScoreTemplate: 'Overall score: {SCORE}/10',
    // 5 area labels (used in both daily and [date] surfaces)
    areaCareer: 'Career',
    areaLove: 'Love',
    areaHealth: 'Health',
